var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 3시간 전","JPN":"前兆プロトコル3時間前","ENG":"3 hours before the Omen Protocol","TWN":"前兆協議3小時前","DEU":"3 hours before the Omen Protocol","FRA":"3 hours before the Omen Protocol"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 상업 지구\\n플라티나 익스프레스 사옥, 옥상","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>商業地区\\nプラチナエクスプレス社、屋上","ENG":"[[","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>商業區\\n白金運通辦公樓，屋頂","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어쩐지 오늘은 평소보다 배달 물량이 많은데?","JPN":"なんかいつもより配達量多くない？","ENG":"Feels like there are more deliveries than usual today, doesn't it?","TWN":"我總覺得今天的配送量比平常還多耶？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그야 라라 선배가 휴가를 썼거든. 그래서 신입들도 할당량도 늘어난 거지.","JPN":"ララ先輩が有休取ったからね。だから新入りのノルマも増えたんだ。","ENG":"That is because Lara took some time off. The new hires got extra quotas too.","TWN":"因為拉拉前輩請假了啊，所以新人的配額也跟著增加了。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으음? 라라 선배가 휴가라고? 그게 정말이야?","JPN":"ん？　ララ先輩が有休？　それマジ？","ENG":"Huh? Lara's on vacation? Really?","TWN":"咦？拉拉前輩請假？真的假的？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"글쎄? 무슨 세계의 운명이 달린 딜리버리 서비스라고 하던데……?","JPN":"さあ？　世界の運命がかかったデリバリーサービスとかなんとか言ってたけど……？","ENG":"Not sure. She said something about a delivery tied to the fate of the world or something like that...","TWN":"對啊？好像說是什麼「攸關世界命運的外送任務」之類的……？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"선배 말이 너무 빨라서 잘 못 알아 들었어.","JPN":"先輩早口すぎて、よく聞き取れなかった。","ENG":"She talks so fast that I could not really catch it.","TWN":"前輩講太快了，我也沒聽清楚。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"세계의 운명이라고…? 하하, 하여간 그 선배도 참 괴짜라니까……?","JPN":"世界の運命……？　はは、まあ先輩って変わり者だしな……","ENG":"The fate of the world...? Haha, she really is a weirdo...","TWN":"世界的命運……？哈哈，前輩果然也是個怪人……？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"하지만 배달 실력은 확실하잖아?","JPN":"でも配達の腕は確かでしょ？","ENG":"Still, you cannot deny her delivery skills.","TWN":"不過她的配送實力真的很厲害啊？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"입사 이래, 플래티넘 랭크의 영광을 단 한 번도 놓친 적 없는 배달 업계의 전설…….","JPN":"入社以来、プラチナランクの栄光を一度も逃したことのない、配達業界の伝説……","ENG":"Since joining, she has never once lost her Platinum Rank. A legend in the delivery business.","TWN":"入職後，從沒失去過白金獎的送貨界傳奇……"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"소문에 따르면, 이 도시 물류의 30% 이상은 선배 혼자 담당하고 있다고 하더라.","JPN":"この都市の物流の3割以上を、先輩1人が担当しているって噂だよ。","ENG":"I heard she handles over thirty percent of this city's logistics all by herself.","TWN":"據說她一個人扛下了這座城市30%以上的物流。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"나도 들었어. 신속, 정확, 안전 그리고 고객님의 미소였나?","JPN":"あ、知ってる。迅速、正確、安全、あとお客様の笑顔だっけ？","ENG":"Yeah, I heard that too. Speed, accuracy, safety, and the customer's smile, right?","TWN":"我也聽說過。迅速、精準、安全，還有顧客的笑容。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"이 회사가 업계 1등 배달 업체가 된 건, 전부 그 선배 덕분이라고 할 수 있지.","JPN":"この会社が配達業界NO.1になれたのは、全部先輩のおかげと言えるね。","ENG":"You could say this company became the top delivery service entirely thanks to her.","TWN":"公司能成為業界第一，可以說全都是前輩的功勞吧。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"물론, 회사 높으신 분들이 그 공로를 알아주는지는 잘 모르겠지만.","JPN":"まあ、会社の偉い人たちがそれをわかってくれてるかは知らないけど。","ENG":"Though I am not sure the higher-ups really recognize her contributions.","TWN":"當然，但就不知道高層到底有沒有認真看待這份功勞了。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아하하… 그건 그렇지…….","JPN":"あはは……それはそうだね……","ENG":"Haha... Yeah, that sounds about right...","TWN":"啊哈哈……這倒也是……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"선배한테 들었는데, 플래티넘 랭크를 받는다고 수당을 더 쳐주는 것 같지는 않더라.","JPN":"先輩の話だと、別にプラチナランクだからって手当が増えるとかでもなさそうだし。","ENG":"I heard from her that Platinum Rank does not even come with extra pay.","TWN":"我聽前輩說過，就算拿到白金獎，好像也不會多給補助。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"켁, 뭐야? 완전 블랙 기업이었잖아?","JPN":"げっ。何それ、超ブラック企業じゃない。","ENG":"What? Seriously? That is a full-on black company.","TWN":"咦？搞什麼，這根本是黑心企業吧？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"레드 리코리스… 편입할 때까지 괜찮은 일자리를 알선해준다더니, 우리를 속였어…….","JPN":"レッドリコリス……編入するまでの間いい仕事を紹介するって言って、ワタシたちを騙したな……","ENG":"Red Lycoris said they would help us find decent jobs until we were transferred, and they totally lied.","TWN":"紅髮莉克麗絲……不是說會在編入前幫我們安排好工作嗎？我們被騙了……"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 그래도 위저드 때보다는 떳떳하게 돈을 벌 수 있잖아?","JPN":"まあでも、ウィザードの時に比べれば、もっと胸を張れる稼ぎ方なのは確かよね。","ENG":"Well, at least it is more honest money than when we were at Wizard.","TWN":"不過嘛，至少比當魔法師賺錢時光明正大多了吧？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"회사 평판이 그다지 좋지는 않지만, 딱히 불법적인 일도 아니고.","JPN":"会社の評判はイマイチだけど、別に違法行為やってるわけじゃないし。","ENG":"The company's reputation is not great, but it's not illegal either.","TWN":"雖然公司名聲不怎麼樣，但也沒做什麼違法的事。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"당장은 관리국 세이프 하우스에서 신세지고 있지만, 언젠가 독립도 해야겠지.","JPN":"今は管理局のセーフハウスに世話になってるけど、いつかは独り立ちしないと。","ENG":"For now, we are staying at the Administration safe house, but someday we'll need to be independent.","TWN":"現在暫時寄住在管理局安全據點，不過總有一天也得獨立。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그리고 무엇보다도… 나, 이 일이 제법 마음에 들거든.","JPN":"あと何より……私、この仕事が結構気に入ってるんだ。","ENG":"And more than anything... I actually like this job.","TWN":"而且最重要的是……我其實滿喜歡這份工作的。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시……?","JPN":"ドロシー……？","ENG":"Dorothy...?","TWN":"桃樂絲……？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 레드 슈즈로 밤 공기를 가르면서, 배달하다 보면 꼭 그때가 생각나서 말이야.","JPN":"このレッドシューズで、夜の空気を突き抜けるように配達してると、以前の自分が思い浮かぶんだ。","ENG":"Cutting through the night air in these Red Shoes while making deliveries always makes me think of back then.","TWN":"每次穿著這雙紅鞋劃破夜晚的空氣奔馳、配送時，總會想起那段時光。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"오로지 달리는 것 하나만을 떠올리던 시절. 그것만이 내 전부였던 시절…….","JPN":"走ることだけに没頭していた……それがすべてだった頃の自分が……","ENG":"Back when all I thought about was running. When that was my entire world...","TWN":"只想著奔跑，奔跑便是一切的時期……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"물론, 이제 와서 더는 그 시절로 돌아갈 수는 없겠지만.","JPN":"あの頃に戻ることはできないけど。","ENG":"Of course, I can't go back to those days anymore.","TWN":"當然，現在已經不可能再回到那時候了。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지금은 이 속도가, 이 다리가…….","JPN":"今はこの速度が、この脚が……","ENG":"But now, this speed, these legs...","TWN":"但現在的速度，這雙腿……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어떤 형태로든, 누군가에게 도움이 될 수 있다는 사실 그 자체가 마음에 들어.","JPN":"どんな形であれ、誰かの役に立てる自分でいさせてくれる。","ENG":"The fact that they can help someone, in any way at all, that is what I like.","TWN":"不論什麼形式，光是能幫上別人的忙這件事本身就讓我很開心。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 일 덕분에 나보다도 더 빠른 사람도 만날 수 있게 됐고.","JPN":"この仕事のおかげで、私より速い人にも出会えたしね。","ENG":"Thanks to this job, I even got to meet people faster than me.","TWN":"也因為這份工作，才能遇見比我更快的人。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그리고 언젠가는 꼭 선배를 이겨보고 싶어.","JPN":"いつか必ず、先輩には勝ってみせたい。","ENG":"And someday, I really want to beat her.","TWN":"而且總有一天，我一定要贏過前輩。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"라라 선배는 공간 도약 카운터야.","JPN":"ララ先輩は空間跳躍カウンターだよ。","ENG":"Lara is a Space-jumping Counter.","TWN":"拉拉前輩可是空間跳躍制裁者。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"네가 아무리 빨라져도 물리법칙을 거스르지 않는 이상, 선배를 이길 수는 없을걸?","JPN":"ドロシーがどんなに速くなっても、物理法則があるかぎり先輩には勝てないよ？","ENG":"No matter how fast you get, unless you break the laws of physics, you can't beat her.","TWN":"不管你再怎麼快，除非你能違反物理法則，不然也贏不了她吧？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그런가? 내 생각은 좀 다른데?","JPN":"そう？　私はそう思わないけど。","ENG":"Is that so? I think differently.","TWN":"是嗎？我倒不這麼認為。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"속도로는 못 이겨도, 한 번쯤 선배한테서 플래티넘 랭크를 빼앗을 수 있지 않을까?","JPN":"速度じゃダメでも、プラチナランクを奪うだけなら、何とかできるんじゃない？","ENG":"Even if I can't beat her in speed, maybe I can steal the Platinum Rank from her at least once.","TWN":"就算速度比不上，難道不能從她手中搶下白金獎一次嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"subtitle","speaker":null,"text":{"KOREA":"L27_1","JPN":"L27_1","ENG":"L27_1","TWN":"L27_1","DEU":"L27_1","FRA":"L27_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};